body, h3, h4, h5, .ch_name, #character_name_pole, b, #send_textarea, .text_pole, button, select, input {
    font-family: "STDongGuanTi", system-ui, sans-serif !important;
    font-weight: normal;
}
.mes_text {
    font-family: "STDongGuanTi", sans-serif !important;
}
.mes_text h1, .mes_text h2 {
    font-family: "PING FANG JIANG NAN TI", "STDongGuanTi", sans-serif !important;
}
.mes_text em, .mes_text q {
    font-family: "STDongGuanTi", serif !important;
}

#character_name_pole { font-size: 1.5em; color: var(--theme-secondary); }
.mes_text blockquote { font-family: "STDongGuanTi", sans-serif; }
.mes_text code { 
    font-family: monospace; 
    background-image: linear-gradient(rgba(245, 248, 252, 0.8), rgba(245, 248, 252, 0.8)), url('https://www.transparenttextures.com/patterns/rice-paper-2.png');
    background-size: auto;
    background-repeat: repeat;
    background-color: var(--theme-ui-element-bg) !important; 
    color: var(--theme-secondary) !important; 
    padding: 2px 5px; 
    border: 1px solid var(--theme-border);
    border-radius: 4px; 
    position: relative;
}

.mes_text code::after { 
    display: none !important;
}

.mes_text blockquote::before { content: '📜 '; }
.mes_text code::before { content: '🖋️ '; }
#chat { background: transparent !important; backdrop-filter: none !important; padding-bottom: 120px !important; }


#top-bar {
    background: none !important;
    border: none !important;
    box-shadow: none !important;
}

