.select2-selection__choice__remove { color: var(--theme-secondary) !important; }
#dialogue_popup_ok, #dialogue_popup_cancel, .popup-button-ok { background-color: var(--theme-ui-element-bg) !important; filter: none !important; }


#form_sheld { position: absolute; bottom: 10px; }
#send_form { width: 90%; max-width: 800px; }
#send_form, body.no-blur #send_form { border-radius: 25px; background-color: rgba(213, 223, 235, 0.8) !important; padding: 10px 15px; backdrop-filter: blur(10px); -webkit-backdrop-filter: blur(10px); border: 1px solid var(--theme-border); box-shadow: 0 4px 20px rgba(20, 40, 68, 0.2); transition: all 0.5s ease; }
#send_form:hover, body.no-blur #send_form:hover { transform: translateY(-5px); background-color: rgba(213, 223, 235, 0.95) !important; box-shadow: 0 8px 30px rgba(20, 40, 68, 0.3); border: 1px solid var(--theme-primary); }
#rightSendForm, #leftSendForm { gap: 10px; }
#send_textarea { clip-path: none !important; border: none !important; background: transparent !important; color: var(--theme-text) !important; }
#nonQRFormItems { position: relative; }
#send_textarea::placeholder { color: transparent !important; text-shadow: none !important; }
#nonQRFormItems:has(#send_textarea:placeholder-shown)::before {
    content: "落笔生花..."; 
    color: var(--theme-text-light); 
    left: 50%;
    position: absolute;
    top: 50%;
    transform: translate(-50%, -50%);
    font-style: italic;
    font-size: 0.9em;
    pointer-events: none;
    z-index: 10;
    white-space: nowrap; 
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: calc(100% - 30px);
}
#options_button::before, #send_but::before, #mes_impersonate::before, #extensionsMenuButton::before { display: none !important; }
#options_button, #send_but, #mes_impersonate, #extensionsMenuButton { width: 32px; height: 32px; background-size: contain; background-repeat: no-repeat; background-position: center; transition: transform 0.2s ease; font-size: 0; border: none; background-color: transparent; }
