div.mes:not([is_user="true"]) {
    position: relative;
    padding-left: 50px; 
    margin-top: 15px;
    border-radius: 8px;
    overflow: visible;
    background-color: rgba(255, 255, 255, 0.85); 
    border: 1px solid var(--theme-border);
    box-shadow: 0 2px 8px rgba(20, 40, 68, 0.1);
}

div.mes:not([is_user="true"]) .avatar { display: none; }


div.mes:not([is_user="true"])::before {
    content: attr(ch_name);
    position: absolute;
    left: 0;
    top: 15px; 
    height: auto; 
    width: 30px;
    padding: 10px 5px;
    background-color: rgba(213, 223, 235, 0.9);
    border: 1px solid var(--theme-border);
    border-radius: 8px;
    writing-mode: vertical-rl;
    text-orientation: mixed;
    text-align: center;
    color: var(--theme-secondary);
    font-weight: bold;
    font-size: 16px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    box-shadow: 0 1px 4px rgba(20, 40, 68, 0.1);
}

div.mes:not([is_user="true"]) .mes_block { display: flex; flex-direction: column; width: 100%; border-radius: 8px; padding: 8px; }
div.mes:not([is_user="true"]) .ch_name .name_text { display: none; }

div.mes:not([is_user="true"]) .mes_img_container {
    display: block; order: 1; width: 100%; min-height: 200px; border-radius: 6px;
    margin-bottom: 8px; position: relative; background-image: var(--ai-header-image);
    background-size: cover; background-position: center; background-repeat: no-repeat;
    border: 1px solid var(--theme-border);
}

div.mes:not([is_user="true"]) .mes_img_container:empty::before { content: ''; }

div.mes:not([is_user="true"]) .mesAvatarWrapper {
    order: 2; display: flex; justify-content: flex-end; align-items: center; gap: 15px;
    font-size: 11px; color: var(--theme-text-light); margin-bottom: 5px; padding: 0 5px;
}


div.mes:not([is_user="true"]) .mesIDDisplay::before { content: '卷 '; }
div.mes:not([is_user="true"]) .tokenCounterDisplay::before { content: '，字数 '; }
div.mes:not([is_user="true"]) .mes_timer::before { content: '，耗时 '; }


div.mes:not([is_user="true"]) .timestamp {
    display: inline-block !important;
    background-color: white;
    color: var(--theme-secondary);
    padding: 2px 8px;
    border-radius: 12px;
    border: 1px solid var(--theme-border);
    box-shadow: 0 1px 2px rgba(0,0,0,0.1);
