div.mes:not([is_user="true"]) .mes_text {
    order: 4; padding: 10px; margin-top: 5px; border-top: 1px solid var(--theme-border);
    color: var(--theme-text);
    background: white url('https://www.transparenttextures.com/patterns/rice-paper-2.png') repeat;
    border-radius: 6px;
