  0%, 100% { box-shadow: 0 0 5px #D5DFEB, 0 0 10px #D5DFEB, 0 0 15px #3966A2; }
  50% { box-shadow: 0 0 10px #7DA3D3, 0 0 20px #3966A2, 0 0 25px #142844; }
}
#typing-indicator span { color: var(--theme-text-light); }
#typing-indicator span::after { content: '正在构思...' !important; }
#typing-indicator .dot-pulse { background-color: #D5DFEB !important; animation: flickerGlow 1.5s infinite ease-in-out; }
.mes_buttons { filter: none !important; }
.swipe_left::before, .swipe_right::before { content: '' !important; }
.swipe_left, .swipe_right { width: 24px; height: 24px; background-size: contain; background-repeat: no-repeat; background-position: center; font-size: 0 !important; }
.swipe_left { background-image: url('https://tc-new.z.wiki/autoupload/1N2_UJVYUo2KjM-_22IFnCfNcKcqEnRmcljopnyJoMs/20250930/Kzib/1346X944/2025-09-30_154603.png/webp'); }
